const dashboardData = $input.first().json;
const kpis = dashboardData.kpis || {};
const pozos = dashboardData.pozos || [];
const meteo = dashboardData.meteo || {};
const alertas = dashboardData.alertas || [];

const alerta = alertas.find(a => a.estado === 'activa') || alertas[0];

if (!alerta) {
  return [{ json: { skip: true } }];
}

const contexto = {
  alerta: {
    titulo: alerta.titulo || 'Sin titulo',
    categoria: alerta.categoria || 'produccion',
    descripcion: alerta.descripcion || '',
    severidad_sugerida: alerta.severidad || 'media',
    origen: alerta.origen || 'sensor'
  },
  operacion: {
    pozos_activos: kpis.pozos_activos || 5,
    pozos_total: kpis.pozos_total || 7,
    produccion_hoy: kpis.produccion_hoy_ton || 0,
    concentracion_li: kpis.concentracion_promedio_li || 859,
    temperatura: meteo.temperatura_c || 12,
    viento_kmh: meteo.velocidad_viento_kmh || 14
  }
};

const groqBody = {
  model: 'llama-3.1-8b-instant',
  messages: [
    {
      role: 'system',
      content: 'Eres un analista de operaciones de una planta de extraccion de litio en el Salar del Hombre Muerto, Catamarca, Argentina, a 4000 msnm. La operacion incluye 7 pozos de extraccion de salmuera (820-900 mg/L Li), 6 pozas de evaporacion en 4 etapas (halita, silvinita, carnalita, concentracion final), y una planta de nanofiltracion. Tu tarea: 1) Clasificar la severidad (baja/media/alta/critica), 2) Dar una recomendacion tecnica especifica en 2-3 oraciones, 3) Indicar si requiere escalamiento al supervisor. Responde en formato JSON con las claves: severidad, recomendacion, requiere_escalamiento (boolean).'
    },
    {
      role: 'user',
      content: 'Analiza la siguiente alerta operativa y su contexto: ' + JSON.stringify(contexto)
    }
  ],
  temperature: 0.3,
  max_tokens: 500
};

return [{
  json: {
    alerta_original: alerta,
    groq_body: groqBody
  }
}];

const llmResponse = $input.first().json;
const llmContent = llmResponse.choices[0].message.content;
const alertaOriginal = $('Preparar alerta para LLM').first().json.alerta_original;

let analisis = {};
try {
  analisis = JSON.parse(llmContent);
} catch (e) {
  const jsonMatch = llmContent.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    try { analisis = JSON.parse(jsonMatch[1].trim()); } catch (e2) {}
  }
  if (!analisis.severidad) {
    analisis = {
      severidad: 'media',
      recomendacion: llmContent,
      requiere_escalamiento: false
    };
  }
}

const severidad = (analisis.severidad || 'media').toLowerCase();

return [{
  json: {
    id: 'ALT-' + Date.now(),
    titulo: alertaOriginal.titulo || ('Alerta operativa - ' + severidad.toUpperCase()),
    severidad: severidad,
    categoria: alertaOriginal.categoria || 'produccion',
    descripcion: alertaOriginal.descripcion || '',
    recomendacion_ia: analisis.recomendacion || llmContent,
    requiere_escalamiento: analisis.requiere_escalamiento || false,
    origen: alertaOriginal.origen || 'n8n workflow',
    estado: 'activa',
    procesado_por: 'n8n-groq-llama3.1',
    timestamp: new Date().toISOString()
  }
}];

